INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07790', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體凝聚力是使所有團體成員聚在一起的力量。下列那一個答案是錯誤的？', '["凝聚力的高低會對團體的溝通品質與數量、成員效忠與滿足、團體目標達成的能力、團體文化的精緻 程度等產生影響", "凝聚力在團體中至少會呈現三種型態：人際整合（interpersonal integration）、結構功能整合（structural integration）、規範性整合（normative integration）", "凝聚力是治療性團體的重要條件，而同質性是形成凝聚力的唯一條件", "凝聚力除表現出隨時隨地不分離的感覺外，也表現在成員間可以呈現其個別性（individuality）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07791', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '人們經過一段時間的互動後，難免會產生歧異或衝突。解決衝突有各種方式，例如：①技巧性運用語言', '["訴諸權威決策", "轉移與延宕", "身體暴力⑤尋求聯盟⑥尊重不同意見⑦語言暴力。請將前述解決衝 突的方式，從低層次到高層次順序排出", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07792', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列各項對於社區睦鄰中心的陳述，何者是錯誤的？', '["社區睦鄰中心是社會工作中最先以社區為單位或是以社區為工作對象的設施，是社會工作最先實施社 區工作方法的一種機構", "臺灣社區睦鄰中心是直接承續英國或美國社區睦鄰中心運動的影響", "社區睦鄰中心對社區工作方法上的貢獻之一是：隨著社區居民實際的需要而發展工作計畫，先舉辦社 區調查再做社區計畫", "改良社區生活、推進社會改革運動，以及社區工作的理論和方法，均是由社區睦鄰中心運動發展而來"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07793', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '福利社區化基本上涵蓋四個向度，請問下列那個答案是錯誤的？', '["作為一種意識型態的實體（as an ideological matter）", "作為一種工作方法（as a method）", "作為一種社會計畫（as a social planning）", "作為一種理念（as an idea）、一種現行的服務措施（as a contemporary practice）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07794', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區參與有程度上的不同，從公民影響公共決策制訂的程度，將參與劃分為非參與、表面作用、公民權等', '["治療（therapy）", "諮詢（consultation）", "公民控制 （citizen control）", "操控（manipulation）⑤通知（informing）⑥夥伴關係（partnership）⑦安撫（placation） ⑧授與權力（delegated power），下列那一個答案是正確的？"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07795', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關福利社區化的基本概念，下列那一個答案是錯誤的？', '["社區照顧是福利社區化的核心工作", "社區工作是福利社區化的工作方法", "「在社區內服務」（service in the community）、「由社區來服務」（service by the community）、「為 社區服務」（service for the community）及「使社區能服務」（service of the community）等四項工作的 結合，才能建構完整福利社區化的服務體系", "社區工作是一種非常本土化福利社區化模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07796', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社區發展的困境？', '["地方政治與社會力量的干預，造成資源錯置及成果無法累積", "缺乏專業人才介入，專業之間也缺乏整合", "社區發展項目日趨多元化，社區產業興盛", "政府積極指導，居民參與率不高"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07797', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區組織的性質包括了公部門和非營利組織的特性，下述何者是錯誤的？', '["社區成員與組織之間的關係是相對嚴謹的", "是自發的、志願性的", "以不營利為目標", "政府與社區外的資源是可以被運用的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07798', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作、社區發展、社區總體營造均是一種工作過程，下列何者並不一定為其必要共同特性？', '["以社區居民為服務對象", "以改善社區生活為目標", "以民主與自治為原則，並以由下而上為工作方法", "由政府推動進行社區照顧"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07799', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '福利社區化要落實，端賴具體可行的方案，以2000年向內政部申請的所有方案看來，下列何者是正確的？', '["因為與政策相關，老人福利方案最受青睞", "兒少婦女成長及休閒方案最創新，已形成以福利意涵為主的社區服務", "身心障礙方案中的親職教育和休閒服務均不屬於社區服務範圍", "志願服務方案被邊緣化"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
